{
  "domains": [
    {
      "id": "JC:Link-Lifecycle-Engine",
      "name": "Link Lifecycle Engine",
      "ubiquitous_language": [
        {
          "term": "Slug",
          "definition": "The six-character short identifier generated for original URLs to enable public sharing without authentication."
        },
        {
          "term": "OriginalUrl",
          "definition": "The target destination address stored and retrieved via the LinkMapping, encrypted at rest using AES-256."
        },
        {
          "term": "LinkMapping",
          "definition": "The unique, non-duplicated association record between a Slug and an OriginalUrl within the content repository."
        },
        {
          "term": "DeletionRequest",
          "definition": "A user-initiated request from a Sharer to remove a specific link from persistent storage and ephemeral cache within 24 hours."
        },
        {
          "term": "DataExportJob",
          "definition": "A system process that exports 100% of stored link data for a requesting user to satisfy GDPR Right to Access requests."
        },
        {
          "term": "LinkExpiryEvent",
          "definition": "A behavioral cluster triggered when a link policy reaches its expiry timestamp, initiating notification attempts for every policy-expiry event."
        }
      ],
      "system_requirement_ids": [
        "SR-001",
        "SR-006",
        "SR-009",
        "SR-010",
        "SR-011",
        "SR-016"
      ]
    },
    {
      "id": "JC:Security-Validation-Gateway",
      "name": "Security Validation Gateway",
      "ubiquitous_language": [
        {
          "term": "MaliciousRequest",
          "definition": "A request identified as malicious or invalid during validation that is rejected to prevent processing."
        },
        {
          "term": "SecureChannel",
          "definition": "The enforced HTTPS transport layer with HSTS headers and HTTP redirection used for all public endpoints."
        },
        {
          "term": "RateLimitCounter",
          "definition": "The enforcement mechanism limiting requests to 1000 per IP per rolling 60-second window, rejecting excess with HTTP 429."
        },
        {
          "term": "ThreatIndicator",
          "definition": "An indicator from the Threat Intelligence Feed used to block submissions and redirects within 5 seconds latency."
        },
        {
          "term": "MaliciousSubmission",
          "definition": "A URL content flagged as malicious before storage in the content repository to prevent persistence of harmful links."
        }
      ],
      "system_requirement_ids": [
        "SR-002",
        "SR-008",
        "SR-013",
        "SR-014",
        "SR-015"
      ]
    },
    {
      "id": "JC:Platform-Reliability-Operations",
      "name": "Platform Reliability Operations",
      "ubiquitous_language": [
        {
          "term": "RedirectLatency",
          "definition": "The P95 latency metric monitored via Prometheus histograms to ensure redirect endpoint latency remains within 100 ms under nominal load."
        },
        {
          "term": "UptimeMetric",
          "definition": "The verified uptime metric calculated over rolling 30-day windows via synthetic probes, ensuring availability ≥ 99.9% including planned maintenance."
        },
        {
          "term": "RecoveryObjective",
          "definition": "The Recovery Time Objective (RTO) target defined for full regional failure recovery, requiring restoration within 15 minutes."
        },
        {
          "term": "AuditLogRecord",
          "definition": "The structured JSON log entry emitted to stdout for ingestion, retaining audit logs for a minimum of 365 days."
        },
        {
          "term": "BackupReplicationJob",
          "definition": "The automated task executed daily to backup data and replicate with zero integrity errors to disaster recovery storage."
        },
        {
          "term": "SystemTimeout",
          "definition": "A system state condition where timeout handling is applied to prevent service crashes during operational delays."
        }
      ],
      "system_requirement_ids": [
        "SR-003",
        "SR-004",
        "SR-005",
        "SR-007",
        "SR-012",
        "SR-017"
      ]
    }
  ]
}
